/**
 * Handler 2: Priority Map
 *
 * Makes the CLAUDE.md > .claude/rules/ > plugin precedence chain explicit.
 * Only injects when multiple source levels are present.
 */

import { logHook } from '../lib/common.js';
import { basename } from 'node:path';
import type { LoadedFile } from './types.js';
import { classifySource } from './classify-source.js';
import type { HookContext } from '../types.js';

const HOOK_NAME = 'instructions-loaded/priority-map';

export function priorityMap(filesLoaded: LoadedFile[], _contents: Map<string, string>): string | null {
  const sources: Record<string, string[]> = {
    project: [],
    rules: [],
    plugin: [],
    unknown: [],
  };

  for (const f of filesLoaded) {
    const source = classifySource(f.path);
    sources[source].push(basename(f.path));
  }

  const activeSources = Object.entries(sources)
    .filter(([key, files]) => files.length > 0 && key !== 'unknown');
  if (activeSources.length < 2) return null;

  const lines: string[] = ['[Rule Precedence] Conflict resolution order:'];
  if (sources.project.length > 0) lines.push(`  1. CLAUDE.md (wins): ${sources.project.join(', ')}`);
  if (sources.rules.length > 0) lines.push(`  2. .claude/rules/ (${sources.rules.length} files): ${sources.rules.join(', ')}`);
  if (sources.plugin.length > 0) lines.push(`  3. Plugin instructions: ${sources.plugin.join(', ')}`);

  logHook(HOOK_NAME, `Priority map: ${activeSources.length} source levels`);
  return lines.join('\n');
}
